for (let i = 0; i < 20; i++) {
  const particle = new THREE.Mesh(smokeGeo, smokeMat.clone());
  particle.visible = false;
  particle.userData = { life: 0, maxLife: 1.5 + Math.random() * 2, speed: 0.8 + Math.random() * 1.5 };
  scene.add(particle);
  smokeParticles.push(particle);
}

const chimneyTop = new THREE.Vector3(1.2, bodyH + 2.9 + 0.3, -0.8);

function emitSmoke() {
  for (const p of smokeParticles) {
    if (!p.visible) {
      p.position.copy(chimneyTop);
      p.position.x += (Math.random() - 0.5) * 0.3;
      p.position.z += (Math.random() - 0.5) * 0.3;
      p.scale.setScalar(0.3);
      p.material.opacity = 0.6;
      p.visible = true;
      p.userData.life = 0;
      return;
    }
  }
}

const clock = new THREE.Clock();
let smokeTimer = 0;

function animate() {
  requestAnimationFrame(animate);
  const dt = Math.min(clock.getDelta(), 0.1);
  controls.update();

  smokeTimer += dt;
  if (smokeTimer > 0.15) { smokeTimer = 0; emitSmoke(); }

  for (const p of smokeParticles) {
    if (!p.visible) continue;
    p.userData.life += dt;
    const progress = p.userData.life / p.userData.maxLife;
    if (progress >= 1) { p.visible = false; continue; }
    p.position.y += p.userData.speed * dt;
    p.position.x += Math.sin(p.userData.life * 3) * 0.2 * dt;
    p.scale.setScalar(0.3 + progress * 2);
    p.material.opacity = 0.5 * (1 - progress);
  }

  renderer.render(scene, camera);
}

window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
});

animate();
